import { HttpClient } from '@angular/common/http';
import { Injectable, inject, signal } from '@angular/core';
import { firstValueFrom } from 'rxjs';
import { environment } from '../../environments/environment';

const STORAGE_KEY = 'td-id-token';

interface MicrosoftLoginResponse {
  url: string;
}

interface MicrosoftCallbackResponse {
  accessToken: string;
  idToken: string;
  expiresOn: string;
  account: {
    homeAccountId: string;
    username: string;
    name: string;
    tenantId: string;
    environment: string;
  };
  scopes: string[];
  tokenType: string;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly http = inject(HttpClient);

  private readonly accessTokenSignal = signal<string | null>(null);

  constructor() {
    this.loadToken();
  }

  getAccessToken(): string | null {
    return this.accessTokenSignal();
  }

  setAccessToken(token: string): void {
    this.accessTokenSignal.set(token);
    try {
      sessionStorage.setItem(STORAGE_KEY, token);
    } catch {
      // ignore
    }
  }

  clearToken(): void {
    this.accessTokenSignal.set(null);
    try {
      sessionStorage.removeItem(STORAGE_KEY);
    } catch {
      // ignore
    }
  }

  async startMicrosoftLogin(): Promise<void> {
    try {
      const response = await firstValueFrom(
        this.http.get<MicrosoftLoginResponse>(`${environment.apiUrl}/v1/auth/microsoft/login`)
      );
      if (!response?.url) {
        throw new Error('Missing login URL.');
      }
      globalThis.location.assign(response.url);
    } catch (error) {
      console.error('Auth login failed:', error);
      alert('No se pudo iniciar sesión con Microsoft.');
    }
  }

  async handleMicrosoftCallback(code: string): Promise<string | null> {
    try {
      const response = await firstValueFrom(
        this.http.get<MicrosoftCallbackResponse>(`${environment.apiUrl}/v1/auth/microsoft/callback`, {
          params: { code }
        })
      );
      if (!response?.idToken) {
        throw new Error('Missing id token.');
      }
      this.setAccessToken(response.idToken);

      // Sincronizar usuario luego de loguearse
      await firstValueFrom(
        this.http.post(`${environment.apiUrl}/v1/auth/sync`, {}, {
          headers: { Authorization: `Bearer ${response.idToken}` }
        })
      );

      return response.idToken;
    } catch (error) {
      console.error('Auth callback failed:', error);
      alert('No se pudo completar la autenticación.');
      return null;
    }
  }

  private loadToken(): void {
    try {
      const token = sessionStorage.getItem(STORAGE_KEY);
      if (token) {
        this.accessTokenSignal.set(token);
      }
    } catch {
      // ignore
    }
  }
}
